+        );
+        assert!(
+            !captured.contains("]("),
+            "expected link markers to be stripped, got: {captured:?}"
+        );
+
+        assert!(
+            segments.iter().any(|s| s.style.is_some()),
+            "expected styled segments, got: {segments:?}"
+        );
+    }
